{"action": "patch", "file_path": "SKILL.md", "name": "event-website-sveltekit", "new_string": "## Supabase Client Library Pattern (`src/lib/supabase.ts`)

The full client module for an event site with ticketing, blocklist, and admin panel follows a consistent structure. Create this file to centralize all Supabase calls:

```typescript
import { createClient } from '@supabase/supabase-js'

const supabaseUrl = 'https://PROJECT_REF.supabase.co'
const supabaseAnonKey = 'sb_publishable_...'

export const supabase = createClient(supabaseUrl, supabaseAnonKey)

// Types
export type TicketTier = 'early_bird' | 'general' | 'vip'
export type TicketStatus = 'pending' | 'confirmed' | 'cancelled' | 'checked_in'

export interface TicketData {
  buyer_name: string
  buyer_email: string
  buyer_phone: string
  quantity: number
  tier: TicketTier
  total_pyg: number
  opted_in_marketing: boolean
}

// Tier config (used in both entradas page and admin)
export const TIER_CONFIG: Record<TicketTier, { label: string; price: number }> = {
  early_bird: { label: 'Pre-Venta', price: 40000 },
  general: { label: 'General', price: 60000 },
  vip: { label: 'VIP', price: 120000 }
}

// Blocklist check (fast, client-side)
export async function checkBlocklist(email: string, phone: string): Promise<{ blocked: boolean; reason?: string }> {
  const { data } = await supabase
    .from('mk_blocklist')
    .select('reason')
    .or(`email.ilike.${email},phone.eq.${phone}`)
    .limit(1)
  if (data && data.length > 0) return { blocked: true, reason: data[0].reason }
  return { blocked: false }
}

// Purchase ticket (blocklist enforced server-side via trigger too)
export async function purchaseTicket(ticket: TicketData): Promise<{ success: boolean; error?: string }> {
  const blocked = await checkBlocklist(ticket.buyer_email, ticket.buyer_phone)
  if (blocked.blocked) return { success: false, error: 'No podemos procesar tu compra.' }

  const { error } = await supabase.from('mk_tickets').insert({
    buyer_name: ticket.buyer_name,
    buyer_email: ticket.buyer_email.toLowerCase(),
    buyer_phone: ticket.buyer_phone,
    quantity: ticket.quantity,
    tier: ticket.tier,
    total_pyg: ticket.total_pyg,
    opted_in_marketing: ticket.opted_in_marketing
  })

  if (error) {
    if (error.message?.includes('INVITADO_NO_BIENVENIDO')) {
      return { success: false, error: 'No podemos procesar tu compra.' }
    }
    return { success: false, error: 'Error al procesar. Intentá de nuevo.' }
  }
  return { success: true }
}

// Admin queries
export async function getTickets(status?: TicketStatus): Promise<any[]> {
  let query = supabase.from('mk_tickets').select('*')
  if (status) query = query.eq('status', status)
  const { data } = await query.order('created_at', { ascending: false })
  return data || []
}

export async function getMarketingList(): Promise<any[]> {
  const { data } = await supabase.from('mk_marketing_list').select('*').order('created_at', { ascending: false })
  return data || []
}

export async function getBlocklist(): Promise<any[]> {
  const { data } = await supabase.from('mk_blocklist').select('*').order('created_at', { ascending: false })
  return data || []
}

export async function updateTicketStatus(id: string, status: TicketStatus): Promise<boolean> {
  const updates: any = { status }
  if (status === 'confirmed') updates.confirmed_at = new Date().toISOString()
  if (status === 'checked_in') updates.checked_in_at = new Date().toISOString()
  const { error } = await supabase.from('mk_tickets').update(updates).eq('id', id)
  return !error
}

export async function addToBlocklist(entry: { email?: string; phone?: string; name?: string; reason: string }): Promise<boolean> {
  const { error } = await supabase.from('mk_blocklist').insert(entry)
  return !error
}

export async function removeFromBlocklist(id: string): Promise<boolean> {
  const { error } = await supabase.from('mk_blocklist').delete().eq('id', id)
  return !error
}

export async function getDashboardStats(): Promise<{ total: number; pending: number; confirmed: number; checked_in: number; revenue: number }> {
  const { data } = await supabase.from('mk_tickets').select('status, total_pyg')
  const tickets = data || []
  return {
    total: tickets.length,
    pending: tickets.filter(t => t.status === 'pending').length,
    confirmed: tickets.filter(t => t.status === 'confirmed').length,
    checked_in: tickets.filter(t => t.status === 'checked_in').length,
    revenue: tickets.filter(t => ['confirmed', 'checked_in'].includes(t.status)).reduce((s, t) => s + t.total_pyg, 0)
  }
}
```

This module is imported by both the public `/entradas` page and the `/admin` page. The anon key is safe to expose because RLS policies + SQL triggers enforce data security.

